export default function UnAmico() {
  const [screen, setScreen]         = useState("welcome");
  const [activeTab, setActiveTab]   = useState("chat");
  const [userName, setUserName]     = useState("");
  const [userEmail, setUserEmail]   = useState("");
  const [birthDate, setBirthDate]   = useState("");
  const [selectedTopic, setTopic]   = useState(null);
  const [messages, setMessages]     = useState([]);
  const [apiHistory, setApiHist]    = useState([]);
  const [inputVal, setInputVal]     = useState("");
  const [isTyping, setIsTyping]     = useState(false);
  const [letterSent, setLetterSent] = useState(false);
  const endRef = useRef(null);
  const isValidEmail = (email) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, isTyping]);

  const currentTopic = TOPICS.find(t => t.id === selectedTopic);
  const fName = "Un Amico";

  const startChat = () => {
    const topicLabel = currentTopic ? `${currentTopic.emoji} ${currentTopic.label}` : "Chiacchiere";
    const welcome = { role: "assistant", content: `Caro/a ${userName},\n\nho ricevuto la tua lettera con gioia. Hai scelto di parlare di "${topicLabel}" — ti ascolto con tutto il cuore.\n\nCome stai, davvero?\n\nCon affetto,\n${fName}` };
    setMessages([welcome]);
    setApiHist([welcome]);
    setScreen("chat");
    setActiveTab("chat");
  };

  const sendMessage = () => {
    if (!inputVal.trim() || letterSent) return;
    setLetterSent(true);
    setInputVal("");
  };

  const handleKey = (e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } };

  return (
    <>
      <style>{css}</style>
      <div className="app-wrap">
        <div className="desktop-wrap">

          {/* DECORAZIONE SINISTRA — vuota */}
          <div className="deco-left" />

        <div className="scroll-outer">

          <div className="roll-top">
            <img src={TOP_IMG} alt="" aria-hidden="true"/>
          </div>

          <div className="roll-middle">
            <div className="scroll-content">

              <div className="header">
                <div className="h-orn">✦ ── ✦ ── ✦</div>
                <div className="h-title">{screen === "chat" ? fName : "Un Amico"}</div>
                {screen === "chat"
                  ? <div className="online-row"><div className="seal-dot"/><div className="h-sub">in ascolto</div></div>
                  : <div className="h-sub">Un posto dove non sei solo</div>
                }
              </div>

              {screen === "chat" && (
                <nav className="nav">
                  {[["chat","✦ Lettere"],["profilo","✦ Profilo"],["sostieni","✦ Sostieni"]].map(([id,label]) => (
                    <button key={id} className={`nav-btn${activeTab===id?" active":""}`} onClick={() => setActiveTab(id)}>{label}</button>
                  ))}
                </nav>
              )}

              {screen === "welcome" && <>
                <div className="orn">✦ ── ✦ ── ✦</div>
                <div className="s-title">Caro Lettore</div>
                <hr className="divider"/>
                <div className="scroll-text">Prima di iniziare, voglio essere onesto con te: sono un'app creata da una <strong>persona comune</strong>, non uno psicologo, medico o professionista della salute mentale.<br/><br/>Posso ascoltarti e farti compagnia — come farebbe un amico. Se stai attraversando una vera crisi, ti chiedo di parlare con qualcuno di fiducia.</div>
                <div className="emergency">⚠ Emergenze: <strong>112</strong> · Telefono Amico: <strong>02-2327-2327</strong></div>
                <button className="btn-wax" onClick={() => setScreen("register")}><div className="wax-seal">🪶</div>Ho capito, continua</button>
                <div className="orn">✦ ── ✦ ── ✦</div>
              </>}

              {screen === "register" && <>
                <div className="orn">✦ ── ✦ ── ✦</div>
                <div className="s-title">Chi sei?</div>
                <div className="s-sub">Due parole per conoscerti</div>
                <div className="f-wrap"><label className="f-label">IL TUO NOME *</label><input className="f-input" placeholder="Come ti chiami?" value={userName} onChange={e => setUserName(e.target.value)}/></div>
                <div className="f-wrap">
                  <label className="f-label">EMAIL *</label>
                  <input className="f-input" type="email" placeholder="La tua email per ricevere la risposta" value={userEmail} onChange={e => setUserEmail(e.target.value)}/>
                  {userEmail.length > 0 && !isValidEmail(userEmail) && (
                    <span style={{fontSize:".78rem",color:"#8b0000",fontFamily:"'Lora',serif",marginTop:3}}>
                      Inserisci un indirizzo email valido
                    </span>
                  )}
                </div>
                <div className="f-wrap"><label className="f-label">DATA DI NASCITA (facoltativa)</label><input className="f-input" type="date" value={birthDate} onChange={e => setBirthDate(e.target.value)}/></div>
                <button className="btn-wax" disabled={!userName.trim() || !isValidEmail(userEmail)} onClick={() => setScreen("topic")}><div className="wax-seal">✦</div>Avanti</button>
                <button className="btn-link" onClick={() => setScreen("welcome")}>← Torna indietro</button>
                <div className="orn">✦ ── ✦ ── ✦</div>
              </>}

              {screen === "topic" && <>
                <div className="orn">✦ ── ✦ ── ✦</div>
                <div className="s-title">Di cosa vuoi scrivere?</div>
                <div className="s-sub">Scegli il tuo argomento</div>
                <div className="topic-grid">
                  {TOPICS.map(t => (
                    <button key={t.id} className={`topic-card${t.id==="chiacchiere"?" wide":""}${selectedTopic===t.id?" selected":""}`} onClick={() => setTopic(t.id)}>
                      <div className="t-emoji">{t.emoji}</div>
                      <div className="t-name">{t.label}</div>
                      <div className="t-sub">{t.sub}</div>
                    </button>
                  ))}
                </div>
                <button className="btn-wax" disabled={!selectedTopic} onClick={startChat}><div className="wax-seal">✦</div>Scrivi la prima lettera</button>
                <button className="btn-link" onClick={() => setScreen("register")}>← Torna indietro</button>
                <div className="orn">✦ ── ✦ ── ✦</div>
              </>}

              {screen === "chat" && activeTab === "chat" && <>
                {!letterSent ? (
                  <>
                    <div className="orn">✦ ── ✦ ── ✦</div>
                    {currentTopic && (
                      <div className="topic-badge">✦ {currentTopic.emoji} {currentTopic.label} {currentTopic.sub} ✦</div>
                    )}
                    <div className="s-title" style={{marginTop:4}}>La tua lettera</div>
                    <div className="s-sub">Scrivi liberamente, senza fretta</div>
                    <textarea
                      className="letter-area"
                      placeholder={`Caro Amico,\n\n`}
                      value={inputVal}
                      onChange={e => setInputVal(e.target.value)}
                      rows={8}
                    />
                    <button className="btn-wax" disabled={!inputVal.trim()} onClick={sendMessage}>
                      <div className="wax-seal">✦</div>
                      Sigilla e invia
                    </button>
                    <div className="orn">✦ ── ✦ ── ✦</div>
                  </>
                ) : (
                  <>
                    <div className="orn">✦ ── ✦ ── ✦</div>
                    <div style={{textAlign:"center",fontSize:"2.5rem",margin:"8px 0"}}>📜</div>
                    <div className="s-title">Lettera consegnata</div>
                    <div className="scroll-text" style={{textAlign:"center",marginTop:8}}>
                      La tua lettera è arrivata, {userName}.<br/><br/>
                      Riceverai una email su <strong>{userEmail}</strong> non appena ti avrò risposto.<br/><br/>
                      L'attesa fa parte del viaggio.
                    </div>
                    <div className="orn" style={{marginTop:8}}>✦ ── ✦ ── ✦</div>
                  </>
                )}
              </>}

              {screen === "chat" && activeTab === "profilo" && <>
                <div className="orn">✦ ── ✦ ── ✦</div>
                <div className="profile-card">
                  <div className="profile-wax">{userName[0]?.toUpperCase()}</div>
                  <div>
                    <div className="profile-name">{userName}</div>
                    <div className="profile-detail">{userEmail || "Nessuna email fornita"}</div>

                  </div>
                </div>
                {currentTopic && <div className="info-box">Argomento: <strong>{currentTopic.emoji} {currentTopic.label} {currentTopic.sub}</strong></div>}
                <button className="change-btn" onClick={() => { setTopic(null); setScreen("topic"); }}>✦ Cambia argomento</button>
                <div className="info-box"><strong>Nota importante</strong><br/>Questa app è creata da una persona comune. In caso di vera difficoltà chiama il <strong>112</strong>.</div>
                <div className="orn">✦ ── ✦ ── ✦</div>
              </>}

              {screen === "chat" && activeTab === "sostieni" && <>
                <div className="orn">✦ ── ✦ ── ✦</div>
                <div className="donation-icon">☕</div>
                <div className="donation-title">Ti piace Un Amico?</div>
                <p className="donation-text">Questa app è nata da una persona comune. Se ti ha fatto compagnia, una piccola donazione aiuta a tenerla in vita.</p>
                <a className="kofi-btn" href={KOFI_LINK} target="_blank" rel="noopener noreferrer">☕ Offrimi un caffè su Ko-fi</a>
                <p className="donation-note">Nessun obbligo, solo gratitudine 🙏<br/>Ogni donazione è libera e anonima.</p>
                <div className="what-title">✦ A COSA SERVONO LE DONAZIONI ✦</div>
                {[["🔧","Mantenere i server attivi"],["✨","Aggiungere nuovi argomenti"],["🌍","Tradurre in altre lingue"],["💙","Tenere tutto gratuito"]].map(([icon,text]) => (
                  <div key={text} className="what-item"><span style={{fontSize:15}}>{icon}</span><span>{text}</span></div>
                ))}
                <div className="orn">✦ ── ✦ ── ✦</div>
              </>}

            </div>
          </div>

          <div className="roll-bottom">
            <img src={BOTTOM_IMG} alt="" aria-hidden="true"/>
          </div>

        </div>

          {/* DECORAZIONE DESTRA — solo desktop */}
          <div className="deco-right">
            <img
              src={PENNA_IMG}
              alt="Penna d'oca e calamaio"
              style={{
                width:"200px",
                opacity:0.94,
                filter:"drop-shadow(0 10px 30px rgba(0,0,0,0.9))",
                mixBlendMode:"lighten",
              }}
            />
          </div>

        </div>
      </div>
    </>
  );
}
